function nearestTripodForBeaker(it,maxDistance=110){if(it?.type!=='beaker')return null;const anchor={x:it.x,y:it.y};return state.workspace.filter(a=>a.type==='tripod').map(tripod=>({tripod,point:tripodGauzeScreenPoint(tripod)})).filter(a=>a.point).map(a=>({...a,d:Math.hypot(anchor.x-a.point.x,anchor.y-a.point.y)})).filter(a=>a.d<=maxDistance).sort((a,b)=>a.d-b.d)[0]||null}
function snapBeakerToTripod(beaker,tripod){beaker.snappedTo=tripod.uid;beaker.x=tripod.x;beaker.y=tripod.y;state.toast='Beaker placed securely on the tripod and gauze.'}
function workspaceHitRegions(it){const anchor=workspaceScreenAnchor(it);if(it.type==='bunsen'){const top=it.lit?it.y-210:it.y-135;hit('workspace-item',it.x-74,top,148,it.y+48-top,it.uid);hit('workspace-item',it.x+42,it.y-102,178,136,it.uid)}else if(it.type==='beaker'&&it.snappedTo)hit('workspace-item',anchor.x-78,anchor.y-126,156,142,it.uid);else hit('workspace-item',anchor.x-66,anchor.y-94,132,154,it.uid)}
function drawWorkspaceItem(it,ghost=false){if(!lab3d.available){ctx.save();if(ghost)ctx.globalAlpha=.58;switch(it.type){case'flask':drawFlask(it.x,it.y,.88,{color:'106,191,211',liquid:.32});break;case'beaker':drawBeaker(it.x-48,it.y-66,96,78,{liquid:.35});break;case'tube':drawTestTube(it.x,it.y-8,.84);break;case'bunsen':drawBunsen(it.x,it.y+51,it.lit);break;case'tripod':drawTripod(it.x,it.y+41,.82);break;case'balance':drawBalance(it.x,it.y,.76,{mass:it.mass||0});break;case'thermometer':drawThermometer(it.x,it.y+32);break;case'phmeter':drawMeter(it.x,it.y,'phmeter');break}ctx.restore()}if(!ghost)workspaceHitRegions(it)}
function drawWorkspace(x,w,benchY){if(!state.workspace.length&&!lab3d.available){ctx.strokeStyle='rgba(74,130,137,.38)';ctx.lineWidth=2;ctx.setLineDash([7,7]);rr(x+w*.18,benchY-235,w*.64,145,18,null,'rgba(74,130,137,.38)');ctx.setLineDash([]);text('YOUR BENCH IS READY',x+w/2,benchY-174,14,C.teal,800,'center');text('Click an item in the equipment library',x+w/2,benchY-146,13,C.muted,600,'center');text('or drag it anywhere into this area',x+w/2,benchY-124,11,C.muted,500,'center')}state.workspace.forEach(it=>drawWorkspaceItem(it));if(state.drag?.kind==='palette')drawWorkspaceItem({type:state.drag.type,x:state.drag.x,y:state.drag.y},true)}
function registerWebGLInteractions(id,cx,cy){const fallback={target:{x:cx+72,y:cy-1},source:{x:cx-155,y:cy-1}};if(id==='free'){const priority={tripod:0,bunsen:1,beaker:3};[...state.workspace].sort((a,b)=>(priority[a.type]??2)-(priority[b.type]??2)).forEach(workspaceHitRegions);state.layout=fallback;return}if(id==='rates'||id==='temp'){const sourceGround=lab3d.projectToScreen(-2.1,0,.1),targetGround=lab3d.projectToScreen(1.25,0,.05);state.layout={source:sourceGround?{x:sourceGround.x,y:sourceGround.y-62}:fallback.source,target:targetGround?{x:targetGround.x,y:targetGround.y-62}:fallback.target};if(!state.pour)hit('reagent',state.layout.source.x-72,state.layout.source.y-96,144,174,'HCl(aq)')}else if(id==='mass'&&state.massStage===2&&state.massLidOn){const lid=lab3d.projectToScreen(1.3,2.58,.05);if(lid){hit('crucible-lid',lid.x-62,lid.y-38,124,76);state.layout={...fallback,lid}}else state.layout=fallback}else state.layout=fallback}
