function drawChemicalTags(id){let massWorld=[1.3,2.16,.05];if(state.massStage===0||state.massStage===7)massWorld=[-2.5,.88,.2];const hydrogenLabel=state.hydrogenStage>=1?'MgCl₂(aq) + H₂(g)':'Mg(s) ribbon';const tags={rates:[['HCl(aq)',[-2.1,0,.1]],['Na₂S₂O₃(aq)',[1.25,0,.05]]],temp:[['HCl(aq)',[-2.1,0,.1]],['NaOH(aq)',[1.25,0,.05]]],salts:[['CuSO₄(aq)',[0,1.76,.1]]],mass:[[state.massStage>=5?'MgO(s)':'Mg(s)',massWorld]],hydrogen:[['dilute HCl(aq)',[-1.8,0,.1]],[hydrogenLabel,[.65,.08,.02]]],co2:[['CaCO₃ + HCl',[-1.75,0,.05]],['Limewater',[1.75,0,.05]]],electro:[['CuCl₂(aq)',[0,0,.1]]],water:[['Water sample',[-1.45,0,.1]],['Distillate',[1.8,0,.1]]]}[id]||[];tags.forEach(([label,world])=>chemicalTag(label,world))}
