function drawFreeLibrary(x,R){ctx.fillStyle='#f4f6f5';ctx.fillRect(x,64,R,H-64);button('EQUIPMENT',x+15,80,125,32,state.tab==='equipment');button('SHELF',x+148,80,112,32,state.tab==='reactants');text(state.tab==='equipment'?'Click to add  •  Drag to place':'Drag onto a flask, beaker or test tube',x+18,125,9.5,C.muted,550);if(state.tab==='equipment'){equipment.forEach((it,i)=>{let yy=143+i*55;rr(x+15,yy,R-30,48,9,'#fff',C.line);ctx.fillStyle=['#5d7fd0','#2c9ab0','#55a27a','#e58b3e','#8063ba','#397e9d','#d85e57','#4a9d76'][i];ctx.beginPath();ctx.arc(x+40,yy+24,16,0,7);ctx.fill();text(it.icon,x+40,yy+24,it.icon==='pH'?8:14,'#fff',800,'center');text(it.name,x+64,yy+18,12,C.ink,750);text(it.sub,x+64,yy+34,9.5,C.muted,500);text('+',x+R-34,yy+24,18,C.teal,700,'center');hit('palette',x+15,yy,R-30,48,it.id)})}else{reactantShelf.forEach((it,i)=>{let yy=143+i*55;rr(x+15,yy,R-30,48,9,'#fff',C.line);ctx.fillStyle=`#${it.color.toString(16).padStart(6,'0')}`;ctx.beginPath();ctx.arc(x+40,yy+24,16,0,7);ctx.fill();text(it.icon,x+40,yy+24,it.icon.length>2?7:10,it.color===0x25282b?'#fff':C.ink,800,'center');text(it.name,x+64,yy+17,11.5,C.ink,750);text(`${it.formula}  •  ${it.unit}`,x+64,yy+34,9.2,C.muted,550);text('↗',x+R-34,yy+24,15,C.teal,700,'center');hit('free-reactant',x+15,yy,R-30,48,it.id)})}rr(x+15,H-73,R-30,48,9,'#e8efed');text('TIP',x+30,H-57,9,C.teal,800);text(state.tab==='equipment'?'Placed equipment stays draggable.':'Drop onto glassware to choose a dose.',x+30,H-40,9.5,C.muted,600)}
function drawDosePanel(){const d=state.dose,r=reactantShelf.find(a=>a.id===d.reactantId),item=state.workspace.find(a=>a.uid===d.targetUid);if(!r||!item)return;const w=390,h=190,x=(W-w)/2,y=(H-h)/2;ctx.fillStyle='rgba(9,27,35,.28)';ctx.fillRect(270,205,W-270-Math.max(260,Math.min(330,W*.23)),H-333);rr(x,y,w,h,16,'#fff','#a9bdc1');text('CHOOSE DOSE',x+24,y+25,10,C.teal,800);text(`${r.name} → ${equipment.find(e=>e.id===item.type)?.name}`,x+24,y+50,15,C.ink,750);text(`${d.amount.toFixed(r.step<1?1:0)} ${r.unit}`,x+w-25,y+50,19,r.unit==='g'?C.orange:C.blue,800,'right');const sx=x+35,sy=y+96,sw=w-70;ctx.strokeStyle='#d2dde0';ctx.lineWidth=8;ctx.lineCap='round';ctx.beginPath();ctx.moveTo(sx,sy);ctx.lineTo(sx+sw,sy);ctx.stroke();const ratio=d.amount/r.max;ctx.strokeStyle=C.teal;ctx.beginPath();ctx.moveTo(sx,sy);ctx.lineTo(sx+sw*ratio,sy);ctx.stroke();ctx.fillStyle='#fff';ctx.strokeStyle=C.teal;ctx.lineWidth=3;ctx.beginPath();ctx.arc(sx+sw*ratio,sy,10,0,7);ctx.fill();ctx.stroke();ctx.lineCap='butt';text(`${r.step} ${r.unit}`,sx,y+121,9,C.muted,600);text(`${r.max} ${r.unit}`,sx+sw,y+121,9,C.muted,600,'right');hit('dose-slider',sx-10,sy-16,sw+20,32,{x:sx,w:sw});rr(x+164,y+142,92,32,8,'#fff',C.line);text('CANCEL',x+210,y+158,11,C.muted,700,'center');hit('dose-cancel',x+164,y+142,92,32);rr(x+266,y+142,99,32,8,C.teal,C.teal);text('ADD DOSE',x+315,y+158,11,'#fff',750,'center');hit('dose-add',x+266,y+142,99,32)}
function massStepIndex(){return state.massStage>=6?3:state.massStage>=3?2:state.massStage>=1?1:0}
function hydrogenStepIndex(){return state.hydrogenStage>=4?3:state.hydrogenStage>=2?2:state.hydrogenStage>=1?1:0}
function rightbar(){const R=Math.max(260,Math.min(330,W*.23)),x=W-R,p=practicals[state.selected],dragLab=p.id==='rates'||p.id==='temp';if(p.id==='free'){drawFreeLibrary(x,R);return}ctx.fillStyle='#f4f6f5';ctx.fillRect(x,64,R,H-64);button('METHOD',x+18,82,92,32,state.tab==='bench');button(p.id==='mass'?'RESULTS':'GRAPH',x+118,82,p.id==='mass'?92:82,32,state.tab==='graph');if(state.tab==='bench'){text('METHOD',x+22,132,10,C.muted,800);const activeStep=p.id==='mass'?massStepIndex():p.id==='hydrogen'?hydrogenStepIndex():Math.floor(state.progress*3);p.steps.forEach((s,i)=>{let yy=155+i*40;ctx.fillStyle=i<=activeStep?C.teal:'#d8e0e2';ctx.beginPath();ctx.arc(x+35,yy,11,0,7);ctx.fill();text(String(i+1),x+35,yy,9,'#fff',800,'center');text(s,x+55,yy,11.2,C.ink,600)});text('REACTANTS — CLICK OR DRAG',x+22,326,9.5,C.muted,800);p.reactants.forEach((r,i)=>{let yy=342+i*31;rr(x+20,yy,R-40,25,6,'#fff',C.line);ctx.fillStyle=p.color;ctx.beginPath();ctx.arc(x+35,yy+12.5,6,0,7);ctx.fill();text(r,x+49,yy+12.5,10.2,C.ink,650);text('↗',x+R-31,yy+12.5,12,C.teal,700,'center');hit('guided-reactant',x+20,yy,R-40,25,r)});const appY=350+p.reactants.length*31;text('APPARATUS',x+22,appY,9.5,C.muted,800);p.gear.slice(0,4).forEach((g,i)=>{rr(x+20+(i%2)*133,appY+15+Math.floor(i/2)*31,123,24,6,'#fff',C.line);text(g,x+29+(i%2)*133,appY+27+Math.floor(i/2)*31,9.5,C.ink,600)});const guideY=Math.min(H-100,appY+86);text('GUIDANCE',x+22,guideY,9.5,C.muted,800);rr(x+20,guideY+15,R-40,70,7,'#e8efed');wrappedText(state.toast,x+32,guideY+32,R-64,9.8,C.ink,600,12,2);text(state.running?'Reaction in progress. Observe':dragLab?'Drag HCl flask onto the receiver.':'Use a reactant card or controls.',x+32,guideY+64,9.5,C.muted,500)}else if(p.id==='mass')drawMassResultsTable(x+18,132,R-36);else drawGraph(x+18,132,R-36,300)}
function drawMassResultsTable(x,y,w){text('RESULTS TABLE',x,y,10,C.muted,800);rr(x,y+20,w,286,8,'#fff',C.line);rr(x+10,y+32,w-20,34,6,'#edf3f2');text('MEASUREMENT',x+20,y+49,8.5,C.muted,800);text('MASS / g',x+w-18,y+49,8.5,C.muted,800,'right');const rows=[['Crucible + magnesium','before heating',state.massBefore],['Crucible + magnesium oxide','after heating',state.massAfter]];rows.forEach((row,i)=>{const ry=y+72+i*76;rr(x+10,ry,w-20,66,6,i?'#f8faf9':'#f4f7f6',C.line);text(row[0],x+20,ry+21,10,C.ink,700);text(row[1],x+20,ry+40,9.4,C.muted,550);text(row[2]==null?'—':row[2].toFixed(2),x+w-18,ry+31,16,row[2]==null?C.muted:(i?C.teal:C.blue),800,'right')});const gain=state.massAfter==null?null:state.massAfter-state.massBefore;rr(x+10,y+230,w-20,63,7,gain==null?'#f1f4f3':'#e7f5ef');text(gain==null?'AFTER HEATING':'MASS INCREASE',x+22,y+249,8.5,gain==null?C.muted:C.teal,800);text(gain==null?'Reweigh to complete the table.':`${gain.toFixed(2)} g of oxygen gained`,x+22,y+272,11,gain==null?C.muted:C.ink,700)}
function drawGraph(x,y,w,h){const s=currentGraphSpec(),top=y+50,left=x+58,right=x+w-14,bottom=y+h-35,gw=right-left,gh=bottom-top;const fmt=(v,dp=0)=>Number(v).toFixed(dp);text('RESULTS GRAPH',x,y,10,C.muted,800);rr(x,y+20,w,h,7,'#fff',C.line);ctx.strokeStyle='#d3dde0';ctx.lineWidth=1;for(let i=0;i<=5;i++){const yy=top+i*gh/5;ctx.beginPath();ctx.moveTo(left,yy);ctx.lineTo(right,yy);ctx.stroke();const value=s.yMax-(s.yMax-s.yMin)*i/5;text(fmt(value,s.yDp),left-7,yy,8,C.muted,550,'right')}for(let i=0;i<=2;i++){const xx=left+i*gw/2,value=s.xMin+(s.xMax-s.xMin)*i/2;text(fmt(value,idDp(s.xMax)),xx,bottom+13,8,C.muted,550,'center')}ctx.strokeStyle=C.ink;ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(left,top);ctx.lineTo(left,bottom);ctx.lineTo(right,bottom);ctx.stroke();ctx.save();ctx.translate(x+13,top+gh/2);ctx.rotate(-Math.PI/2);text(s.yLabel,0,0,9,C.muted,650,'center');ctx.restore();text(s.xLabel,left+gw/2,y+h+7,9,C.muted,650,'center');if(state.points.length){ctx.strokeStyle=C.teal;ctx.lineWidth=3;ctx.beginPath();state.points.forEach((p,i)=>{const px=left+p.x*gw,py=bottom-p.y*gh;i?ctx.lineTo(px,py):ctx.moveTo(px,py)});ctx.stroke();state.points.forEach(p=>{ctx.fillStyle=C.orange;ctx.beginPath();ctx.arc(left+p.x*gw,bottom-p.y*gh,3.5,0,Math.PI*2);ctx.fill()})}text(`${state.points.length} reading${state.points.length===1?'':'s'} recorded`,x,y+h+38,11,C.muted,600)}
function idDp(max){return max<10?1:0}
function draw(){regions=[];ctx.clearRect(0,0,W,H);header();sidebar();main();rightbar();if(state.dose)drawDosePanel();visibleCtx.save();visibleCtx.setTransform(1,0,0,1,0,0);visibleCtx.globalCompositeOperation='copy';visibleCtx.drawImage(buffer,0,0);visibleCtx.restore();if(!state.dose)lab3d.render(performance.now(),state,practicals[state.selected])}
function addWorkspaceItem(type,x=null,y=null){const slot=state.workspace.length,benchY=H-128;state.workspace.push({uid:state.nextItem++,type,x:x??(345+(slot%5)*105),y:y??(benchY-64-Math.floor(slot/5)*105),lit:false,mass:0,contents:[],snappedTo:null,temperature:20,heating:false});state.toast=`${equipment.find(e=>e.id===type)?.name||type} added — drag it to reposition.`}
function positionWorkspaceItem(it,pointerX,pointerY,dx=0,dy=0){const R=Math.max(260,Math.min(330,W*.23));it.x=Math.max(310,Math.min(W-R-42,pointerX-dx));it.y=Math.max(285,Math.min(H-145,pointerY-dy))}
function containerItems(){return state.workspace.filter(it=>['flask','beaker','tube'].includes(it.type))}
function workspaceHeatLinks(){return state.workspace.filter(it=>it.type==='beaker'&&it.snappedTo&&it.contents?.length).map(beaker=>{const tripod=state.workspace.find(a=>a.uid===beaker.snappedTo&&a.type==='tripod');if(!tripod)return null;const burner=state.workspace.find(a=>a.type==='bunsen'&&a.lit&&Math.hypot(a.x-tripod.x,a.y-tripod.y)<115);return burner?{beaker,tripod,burner}:null}).filter(Boolean)}
function openDose(reactantId,targetUid){const r=reactantShelf.find(a=>a.id===reactantId);if(!r)return;state.dose={reactantId,targetUid,amount:Math.min(r.max,r.unit==='g'?5:25)};state.toast=`Choose how much ${r.formula} to add.`}
function applyDose(){const d=state.dose,r=reactantShelf.find(a=>a.id===d?.reactantId),item=state.workspace.find(a=>a.uid===d?.targetUid);if(!r||!item)return;item.contents??=[];item.contents.push({id:r.id,name:r.name,amount:d.amount,unit:r.unit,color:r.color});if(r.unit==='mL')state.volume+=d.amount;else item.mass=(item.mass||0)+d.amount;state.ph=Math.max(0,Math.min(14,(state.ph+r.ph)/2));state.toast=`Added ${d.amount.toFixed(r.step<1?1:0)} ${r.unit} ${r.formula} to the ${equipment.find(e=>e.id===item.type)?.name}.`;state.dose=null}
function resetMassPractical(){state.running=false;state.complete=false;state.burner=false;state.time=0;state.progress=0;state.points=[];state.temp=25;state.ph=7;state.massStage=0;state.massLidOn=true;state.massTransfer=null;state.massBefore=4.01;state.massAfter=null;state.tab='bench';state.toast='Initial weighing: crucible, lid and magnesium ribbon = 4.01 g. Move the crucible to the tripod.'}
function removeMassLid(){if(state.massStage!==2||!state.massLidOn)return;state.massLidOn=false;state.massStage=3;state.toast='Lid removed. The coiled magnesium ribbon is visible and ready to heat.'}
function activateMass(label){if(label==='MOVE TO TRIPOD'&&state.massStage===0){state.massStage=1;state.massTransfer={direction:'toTripod',t:0};state.toast='Transferring the weighed crucible carefully to the wire gauze.'}else if(label==='REMOVE LID')removeMassLid();else if(label==='LIGHT BUNSEN'&&state.massStage===3){state.massStage=4;state.burner=true;state.running=true;state.time=0;state.progress=0;state.toast='Magnesium is burning in oxygen with an intense white glow.'}else if(label==='COOL & REWEIGH'&&state.massStage===5){state.massStage=6;state.massTransfer={direction:'toBalance',t:0};state.temp=70;state.toast='The flaky white magnesium oxide is cooling and moving to the balance.'}else if(label==='RESET PRACTICAL')resetMassPractical();else if(label==='RECORD BEFORE')state.toast='Initial mass recorded: 4.01 g.';else if(label==='RECORD AFTER'&&state.massAfter!=null)state.toast=`Final mass recorded: ${state.massAfter.toFixed(2)} g.`;else if(label==='RESULTS')state.tab='graph'}
function resetHydrogenPractical(){state.running=false;state.complete=false;state.time=0;state.progress=0;state.points=[];state.temp=25;state.ph=7;state.volume=0;state.transferred=0;state.hydrogenStage=0;state.hydrogenTimer=0;state.hydrogenAudioPlayed=false;state.hydrogenGas=0;state.tab='bench';state.toast='A coil of magnesium ribbon is ready in the test tube. Add the dilute hydrochloric acid.'}
function activateHydrogen(label){primePopAudio();if(label==='POUR DILUTE HCl'&&state.hydrogenStage===0){state.hydrogenStage=1;state.hydrogenTimer=0;state.running=true;state.time=0;state.toast='Pouring dilute hydrochloric acid onto the magnesium ribbon.'}else if(label==='TEST WITH LIT SPLINT'&&state.hydrogenStage===3){state.hydrogenStage=4;state.hydrogenTimer=0;state.running=true;state.hydrogenAudioPlayed=false;state.toast='Thumb removed — the lit splint is approaching the trapped hydrogen.'}else if(label==='RESET PRACTICAL'&&state.hydrogenStage===5)resetHydrogenPractical();else if(label==='RECORD'){state.points.push(graphReading());state.toast='Hydrogen gas volume recorded.'}}
function applyGuidedReactant(name){const id=practicals[state.selected].id;if(id==='mass'){state.toast=name==='Oxygen'?'Oxygen is supplied by the air around the open crucible.':'The magnesium ribbon is already weighed inside the covered crucible.';return}if(id==='hydrogen'){state.toast=name.toLowerCase().includes('acid')?'Use POUR DILUTE HCl to animate the measured acid addition.':'The magnesium ribbon is already coiled in the test tube.';return}state.lastReactant=name;state.running=true;state.progress=Math.max(.14,state.progress);state.transferred=Math.min(1,state.transferred+.28);state.toast=`${name} added to the correct container — observe the reaction.`;if(name.toLowerCase().includes('hydrochloric'))state.ph=Math.max(1,state.ph-2);if(name.toLowerCase().includes('sodium hydroxide'))state.ph=Math.min(13,state.ph+3)}
function activate(label){const id=practicals[state.selected].id;if(id==='mass'&&['MOVE TO TRIPOD','TRANSFERRING…','REMOVE LID','LIGHT BUNSEN','HEATING…','COOL & REWEIGH','REWEIGHING…','RESET PRACTICAL','RECORD BEFORE','INITIAL MASS SAVED','LID CLOSED','READY TO HEAT','MAGNESIUM BURNING','MgO FORMED','BALANCE SETTLING','RECORD AFTER','RESULTS'].includes(label)){activateMass(label);draw();return}if(id==='hydrogen'&&['POUR DILUTE HCl','POURING…','COLLECTING H₂…','TEST WITH LIT SPLINT','IGNITING…','RESET PRACTICAL','Mg RIBBON READY','ACID TRANSFER','THUMB SEALED','H₂ COLLECTED','SQUEAKY POP!','TEST COMPLETE','RECORD'].includes(label)){activateHydrogen(label);draw();return}if(label==='EQUIPMENT')state.tab='equipment';else if(label==='SHELF')state.tab='reactants';else if(label==='CLEAR BENCH'){state.workspace=[];state.dose=null;state.toast='Bench cleared. Choose new equipment from the library.'}else if(label==='UNDO LAST'){state.workspace.pop();state.toast=state.workspace.length?'Last item removed.':'The workspace is blank.'}else if(label==='START'||label==='RESET'){state.running=!state.running;state.time=0;state.progress=0;state.complete=false;state.points=[];state.toast=state.running?'Experiment started — observe the apparatus.':'Apparatus reset and ready.'}else if(label==='LIGHT BUNSEN'||label==='EXTINGUISH'){state.burner=!state.burner;state.running=state.burner;state.toast=state.burner?'Bunsen lit: roaring blue flame, air hole open.':'Gas tap closed and flame extinguished.'}else if(label==='APPLY HEAT'){state.burner=true;state.running=true;state.toast='Heating applied — observe the live measurement.'}else if(label==='ADD REAGENT'){state.running=true;state.toast=id==='rates'||id==='temp'?'Drag the HCl(aq) flask to the receiver.':'Reagent added — observe the reaction.';state.progress=Math.max(.08,state.progress)}else if(label==='RECORD'){state.points.push(graphReading());state.toast='Reading added to the results graph.'}else if(label==='METHOD')state.tab='bench';else if(label==='GRAPH'||label==='RESULTS')state.tab='graph';draw()}
canvas.addEventListener('pointermove',e=>{if(state.drag){const moved=Math.hypot(e.offsetX-state.drag.startX,e.offsetY-state.drag.startY)>7;state.drag.moved=state.drag.moved||moved;state.drag.x=e.offsetX;state.drag.y=e.offsetY;if(state.drag.kind==='workspace'){const it=state.workspace.find(a=>a.uid===state.drag.uid);if(it){if(state.drag.moved&&it.type==='beaker'&&it.snappedTo){const anchor=workspaceScreenAnchor(it);it.snappedTo=null;it.x=anchor.x;it.y=anchor.y}positionWorkspaceItem(it,e.offsetX,e.offsetY,state.drag.dx,state.drag.dy);state.drag.snapUid=it.type==='beaker'?nearestTripodForBeaker(it)?.tripod.uid||null:null}}else if(state.drag.kind==='free-reactant'){const target=containerItems().map(it=>{const anchor=workspaceScreenAnchor(it);return {it,d:Math.hypot(e.offsetX-anchor.x,e.offsetY-anchor.y)}}).sort((a,b)=>a.d-b.d)[0];state.drag.targetUid=target&&target.d<92?target.it.uid:null}else if(state.drag.kind==='dose-slider'&&state.dose){const r=reactantShelf.find(a=>a.id===state.dose.reactantId),ratio=Math.max(0,Math.min(1,(e.offsetX-state.drag.sliderX)/state.drag.sliderW));state.dose.amount=Math.max(r.step,Math.round((ratio*r.max)/r.step)*r.step)}else if(state.drag.kind==='HCl(aq)'&&state.layout&&Math.hypot(e.offsetX-state.layout.target.x,e.offsetY-state.layout.target.y)<190)state.drag.nearTarget=true;canvas.style.cursor='grabbing';draw();return}const r=regions.findLast(a=>e.offsetX>=a.x&&e.offsetX<=a.x+a.w&&e.offsetY>=a.y&&e.offsetY<=a.y+a.h);canvas.style.cursor=r&&['palette','free-reactant','guided-reactant','reagent','workspace-item','dose-slider'].includes(r.id)?'grab':r?'pointer':'default'});
canvas.addEventListener('pointerdown',e=>{const r=regions.findLast(a=>e.offsetX>=a.x&&e.offsetX<=a.x+a.w&&e.offsetY>=a.y&&e.offsetY<=a.y+a.h);if(!r)return;if(r.id==='dose-add'){applyDose();draw()}else if(r.id==='dose-cancel'){state.dose=null;state.toast='Dose cancelled.';draw()}else if(r.id==='dose-slider'){const reagent=reactantShelf.find(a=>a.id===state.dose?.reactantId),ratio=Math.max(0,Math.min(1,(e.offsetX-r.data.x)/r.data.w));if(reagent)state.dose.amount=Math.max(reagent.step,Math.round((ratio*reagent.max)/reagent.step)*reagent.step);state.drag={kind:'dose-slider',x:e.offsetX,y:e.offsetY,startX:e.offsetX,startY:e.offsetY,sliderX:r.data.x,sliderW:r.data.w,moved:false};canvas.setPointerCapture?.(e.pointerId);draw()}else if(r.id==='practical'){state.selected=r.data;state.running=false;state.complete=false;state.progress=0;state.points=[];state.temp=practicals[r.data].id==='free'?20:25;state.volume=0;state.ph=7;state.burner=false;state.transferred=0;state.pour=null;state.drag=null;state.dose=null;state.lastReactant=null;state.particles=[];state.tab=practicals[r.data].id==='free'?'equipment':'bench';if(practicals[r.data].id==='mass')resetMassPractical();else if(practicals[r.data].id==='hydrogen')resetHydrogenPractical();else state.toast=practicals[r.data].id==='free'?'Click equipment to add it, or drag it onto the bench.':`${practicals[r.data].gear.join(', ')} loaded onto the bench.`;draw()}else if(r.id==='crucible-lid'){removeMassLid();draw()}else if(r.id==='button')activate(r.data);else if(r.id==='palette'){state.drag={kind:'palette',type:r.data,x:e.offsetX,y:e.offsetY,startX:e.offsetX,startY:e.offsetY,moved:false};canvas.setPointerCapture?.(e.pointerId);draw()}else if(r.id==='free-reactant'){state.drag={kind:'free-reactant',reactantId:r.data,x:e.offsetX,y:e.offsetY,startX:e.offsetX,startY:e.offsetY,moved:false,targetUid:null};canvas.setPointerCapture?.(e.pointerId);draw()}else if(r.id==='guided-reactant'){state.drag={kind:'guided-reactant',name:r.data,x:e.offsetX,y:e.offsetY,startX:e.offsetX,startY:e.offsetY,moved:false};canvas.setPointerCapture?.(e.pointerId);draw()}else if(r.id==='workspace-item'){const it=state.workspace.find(a=>a.uid===r.data);if(it){const anchor=workspaceScreenAnchor(it);state.drag={kind:'workspace',uid:it.uid,x:e.offsetX,y:e.offsetY,startX:e.offsetX,startY:e.offsetY,dx:e.offsetX-anchor.x,dy:e.offsetY-anchor.y,moved:false,snapUid:null,origin:{x:it.x,y:it.y,snappedTo:it.snappedTo||null}};canvas.setPointerCapture?.(e.pointerId)}}else if(r.id==='reagent'&&!state.pour){state.drag={kind:'HCl(aq)',x:e.offsetX,y:e.offsetY,startX:e.offsetX,startY:e.offsetY};canvas.setPointerCapture?.(e.pointerId);state.toast='Move the flask close to the receiver, then release.';draw()}});
canvas.addEventListener('pointerup',e=>{if(!state.drag)return;const d=state.drag;if(d.kind==='palette'){const R=Math.max(260,Math.min(330,W*.23)),inside=e.offsetX>285&&e.offsetX<W-R&&e.offsetY>205&&e.offsetY<H-120;addWorkspaceItem(d.type,d.moved&&inside?e.offsetX:null,d.moved&&inside?e.offsetY:null)}else if(d.kind==='workspace'){const it=state.workspace.find(a=>a.uid===d.uid),releaseMoved=d.moved||Math.hypot(e.offsetX-d.startX,e.offsetY-d.startY)>7;if(it&&releaseMoved){positionWorkspaceItem(it,e.offsetX,e.offsetY,d.dx,d.dy);const snap=d.snapUid&&state.workspace.find(a=>a.uid===d.snapUid&&a.type==='tripod');if(it.type==='beaker'&&snap)snapBeakerToTripod(it,snap);else state.toast='Equipment repositioned.'}else if(it&&it.type==='bunsen'){it.lit=!it.lit;state.toast=it.lit?(workspaceHeatLinks().length?'Gas valve open — Bunsen lit and heating the beaker contents.':'Gas valve open — Bunsen lit. Place it below a loaded tripod to heat.'):'Gas valve closed — Bunsen extinguished.'}else state.toast='Equipment selected.'}else if(d.kind==='free-reactant'){const targetUid=d.targetUid||(!d.moved?containerItems()[0]?.uid:null);if(targetUid)openDose(d.reactantId,targetUid);else state.toast='Add a flask, beaker or test tube, then drop the reactant onto it.'}else if(d.kind==='guided-reactant'){const R=Math.max(260,Math.min(330,W*.23)),inside=e.offsetX>270&&e.offsetX<W-R&&e.offsetY>205&&e.offsetY<H-120;if(!d.moved||inside)applyGuidedReactant(d.name);else state.toast='Drop the reactant over the main container.'}else if(d.kind==='HCl(aq)'){const near=d.nearTarget||(state.layout&&Math.hypot(d.x-state.layout.target.x,d.y-state.layout.target.y)<190);if(near){state.pour={t:0};state.running=true;state.toast='Pouring HCl(aq) — reaction initiated.'}else state.toast='Move closer to the highlighted receiving flask.'}state.drag=null;draw()});
canvas.addEventListener('pointercancel',()=>{if(!state.drag)return;if(state.drag.kind==='workspace'){const it=state.workspace.find(a=>a.uid===state.drag.uid);if(it&&state.drag.origin)Object.assign(it,state.drag.origin)}state.toast='Interaction cancelled.';state.drag=null;draw()});
document.addEventListener('keydown',e=>{if(e.key.toLowerCase()==='f'){document.fullscreenElement?document.exitFullscreen():canvas.requestFullscreen()}if(e.key==='Escape'&&document.fullscreenElement)document.exitFullscreen()});
function update(dt,skipDraw=false){
 state.flamePhase+=dt*3.4;
 const id=practicals[state.selected].id,free=id==='free',heatLinks=free?workspaceHeatLinks():[],heated=new Set(heatLinks.map(link=>link.beaker.uid));
 if(free){let hottest=20;for(const it of state.workspace){if(it.type!=='beaker')continue;it.temperature??=20;it.heating=heated.has(it.uid);it.temperature=it.heating?Math.min(100,it.temperature+dt*6.5):Math.max(20,it.temperature-dt*1.35);hottest=Math.max(hottest,it.temperature)}state.temp=hottest}
 let animating=state.running||state.burner||state.pour||state.drag||state.massTransfer||state.workspace.some(it=>it.type==='bunsen'&&it.lit)||heatLinks.length||state.workspace.some(it=>it.type==='beaker'&&(it.temperature||20)>20.05);
 if(state.pour){state.pour.t+=dt;state.transferred=Math.min(1,state.pour.t/1.55);if(state.layout&&Math.random()<dt*25)state.particles.push({x:state.layout.target.x+(Math.random()-.5)*55,y:state.layout.target.y+25-Math.random()*18,r:2+Math.random()*3,life:1,color:'rgba(234,251,255,.9)',vy:-14-Math.random()*20});if(state.pour.t>1.65){state.pour=null;state.toast='Transfer complete — HCl mixed with the solution.';state.progress=Math.max(.2,state.progress)}}
 state.particles.forEach(pt=>{pt.y+=(pt.vy||-9)*dt;pt.x+=Math.sin(state.flamePhase+pt.y)*dt*4;pt.life-=dt*.62});state.particles=state.particles.filter(pt=>pt.life>0);
 if(id==='mass'&&state.massTransfer){state.massTransfer.t+=dt;state.temp=Math.max(25,state.temp-dt*22);if(state.massTransfer.t>=1.55){const direction=state.massTransfer.direction;state.massTransfer=null;if(direction==='toTripod'){state.massStage=2;state.toast='Crucible placed on the gauze. Click its rounded lid to reveal the magnesium ribbon.'}else{state.massStage=7;state.massAfter=4.18;state.complete=true;state.temp=25;state.toast='Final mass settled at 4.18 g. The increase is oxygen combined with magnesium.'}}if(!skipDraw)draw();return}
 if(id==='mass'&&state.massStage===4&&state.running){state.time+=dt;state.progress=Math.min(1,state.progress+dt/7);state.temp=25+68*state.progress;if(state.progress>=1){state.running=false;state.burner=false;state.massStage=5;state.temp=93;state.toast='Reaction complete: flaky white magnesium oxide has formed. Cool it, then reweigh.'}if(!skipDraw)draw();return}
 if(id==='hydrogen'&&state.running&&state.hydrogenStage>=1&&state.hydrogenStage<=4){state.time+=dt;state.hydrogenTimer+=dt;if(state.hydrogenStage===1){const q=Math.min(1,state.hydrogenTimer/2.25);state.transferred=q;state.progress=.04+.11*q;state.ph=7-5.5*q;state.temp=25+1.5*q;if(q>=1){state.hydrogenStage=2;state.hydrogenTimer=0;state.toast='The acid is reacting with magnesium. A thumb seals the tube while hydrogen collects.'}}else if(state.hydrogenStage===2){const q=Math.min(1,state.hydrogenTimer/3.4);state.hydrogenGas=40*q;state.volume=state.hydrogenGas;state.progress=.15+.65*q;state.temp=26.5+2.5*q;const last=state.points.at(-1);if(!last||state.time-last.t>.7)state.points.push(graphReading());if(q>=1){state.hydrogenStage=3;state.hydrogenTimer=0;state.running=false;state.hydrogenGas=40;state.volume=40;state.progress=.8;state.points.push(graphReading());state.toast='Hydrogen collected. Keep the tube sealed, then test it with the lit splint.'}}else if(state.hydrogenStage===4){const q=Math.min(1,state.hydrogenTimer/1.25);if(state.hydrogenTimer>=.38)playSqueakyPop();const burn=Math.max(0,Math.min(1,(state.hydrogenTimer-.38)/.52));state.hydrogenGas=40*(1-burn);state.volume=state.hydrogenGas;state.progress=.8+.2*q;state.temp=29+7*Math.sin(q*Math.PI);if(q>=1){state.hydrogenStage=5;state.running=false;state.complete=true;state.hydrogenGas=0;state.volume=0;state.progress=1;state.temp=25;state.toast='Squeaky pop confirmed: the hydrogen ignited and the flame travelled rapidly up the tube.'}}if(!skipDraw)draw();return}
 if(free||!state.running||state.complete){if(animating&&!skipDraw)draw();return}
 state.time+=dt;state.progress=Math.min(1,state.progress+dt/10);
 if(id==='temp')state.temp=25+17*Math.sin(state.progress*Math.PI/2);else if(id==='rates')state.temp=25+3*state.progress;else if(id==='water')state.temp=25+72*state.progress;else if(id==='salts')state.temp=25+(state.burner?68:8)*state.progress;else state.temp=25+6*state.progress;
 state.ph=id==='temp'?Math.max(1,13-12*state.progress):id==='salts'?2+3*state.progress:7;
 if(Math.floor(state.time*2)%2===0&&state.points.length<12){const last=state.points.at(-1);if(!last||state.time-last.t>1.2)state.points.push(graphReading())}
 if(state.progress>=1){state.complete=true;state.toast='Complete — review your plotted results.'}
 if(!skipDraw)draw()
}
let last=performance.now();function loop(now){let dt=Math.min(.05,(now-last)/1000);last=now;if(!window.__manualSimulationTime)update(dt);requestAnimationFrame(loop)}
window.advanceTime=ms=>{for(let t=0;t<ms;t+=16.67)update(1/60,true);draw()};
