 const massLidTarget=id==='mass'&&state.massStage===2&&state.massLidOn&&state.layout?.lid?{x:Math.round(state.layout.lid.x),y:Math.round(state.layout.lid.y)}:null;
 const stageNames=['ready','pouring acid','collecting hydrogen','sealed and ready to test','igniting hydrogen','test complete'],thumbSealing=id==='hydrogen'&&(state.hydrogenStage===0||state.hydrogenStage===2||state.hydrogenStage===3||(state.hydrogenStage===1&&state.hydrogenTimer>1.85));
 return JSON.stringify({coordinates:'origin top-left, x right, y down',renderer:{...lab3d.info,legacy_2d_apparatus:!lab3d.available},mode:free?'free workspace':'guided practical',practical:p.title,objective:p.objective,symbol_equation:p.eq,word_equation:p.word,tab:state.tab,running:state.running,complete:state.complete,dragging:state.drag?.kind||null,pouring:!!state.pour,bunsen_lit:free?freeBurnerLit:state.burner,magnesium_glow:id==='mass'&&state.massStage===4&&state.running,dose_dialog:state.dose&&{reactant:state.dose.reactantId,amount:state.dose.amount,target:state.dose.targetUid},tripod_gauze_snap_targets:snapTargets,workspace_items:state.workspace.map(it=>({uid:it.uid,type:it.type,x:Math.round(it.x),y:Math.round(it.y),lit:!!it.lit,snapped_to:it.snappedTo||null,temperature_c:+(it.temperature||20).toFixed(1),heating:!!it.heating,...(it.type==='bunsen'?{gas_tap:'white enamel',gas_valve:it.lit?'open':'closed',hose:'attached'}:{}),contents:it.contents})),mass_practical:id==='mass'?{stage:state.massStage,lid_on:state.massLidOn,lid_click_target:massLidTarget,material:state.massStage>=5?'flaky white magnesium oxide':'coiled magnesium ribbon',transfer:state.massTransfer?.direction||null,before_g:state.massBefore,after_g:state.massAfter}:null,hydrogen_practical:id==='hydrogen'?{stage:state.hydrogenStage,phase:stageNames[state.hydrogenStage],timer_s:+state.hydrogenTimer.toFixed(2),test_tube_contents:state.hydrogenStage===0?'coiled magnesium ribbon':'magnesium ribbon + dilute hydrochloric acid',measuring_cylinder_hcl_ml:+(15*(1-state.transferred)).toFixed(1),thumb_sealing:thumbSealing,bubbles_visible:state.hydrogenStage===1||state.hydrogenStage===2,gas_volume_cm3:+state.hydrogenGas.toFixed(1),lit_splint_visible:state.hydrogenStage===4,flame_travelling:state.hydrogenStage===4&&state.hydrogenTimer>=.4&&state.hydrogenTimer<.88,squeaky_pop_played:state.hydrogenAudioPlayed}:null,time_s:+state.time.toFixed(1),temperature_c:+state.temp.toFixed(1),volume_ml:+state.volume.toFixed(1),ph:+state.ph.toFixed(1),progress:+state.progress.toFixed(2),chromatography_dyes:chrom?{separation:+state.progress.toFixed(2),colours:['magenta','blue','yellow','green']}:null,graph_axes:spec&&{x:spec.xLabel,y:spec.yLabel},results_columns:id==='mass'?['measurement','mass / g']:null,graph_readings:state.points.length,last_graph_reading:state.points.at(-1)&&{x:+state.points.at(-1).xValue.toFixed(2),y:+state.points.at(-1).yValue.toFixed(2)},guidance:state.toast,controls:free?['Equipment and Reactant Shelf tabs','click or drag equipment','drag beaker onto tripod gauze to snap','align a lit Bunsen below the tripod to heat contents','drag reactant onto compatible glassware','dose slider then ADD DOSE','click Bunsen gas tap to open/close valve','CLEAR BENCH','UNDO LAST','F fullscreen']:id==='mass'?['MOVE TO TRIPOD','click crucible lid','LIGHT BUNSEN','COOL & REWEIGH','RESULTS','METHOD','F fullscreen']:id==='hydrogen'?['POUR DILUTE HCl','TEST WITH LIT SPLINT','RECORD','GRAPH','METHOD','F fullscreen']:['icon practical cards','click or drag reactants below method','START/RESET','APPLY HEAT','RECORD','METHOD','GRAPH','F fullscreen']})
